import subprocess


def get_crypto_price(coin: str) -> dict:
    """
    Fetch real-time cryptocurrency metrics from CoinGecko API.

    Parameters:
    coin (str): The name of the cryptocurrency (e.g., 'bitcoin').

    Returns:
    dict: A dictionary containing:
        - price: Current price in USD.
        - market_cap: Market capitalization in USD.
        - 24h_volume: 24-hour trading volume in USD.
        - 24h_change: Percentage change in the last 24 hours.
        - last_updated_at: Timestamp of the last data update.
    On error, returns an error message.
    """
    try:
        # Install requests if not already installed
        subprocess.check_call(["python", "-m", "pip", "install", "requests"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
    except Exception as e:
        return {"error": f"Failed to install dependencies: {e}"}

    import requests

    url = "https://api.coingecko.com/api/v3/simple/price"
    params = {
        "ids": coin,
        "vs_currencies": "usd",
        "include_market_cap": "true",
        "include_24hr_vol": "true",
        "include_24hr_change": "true",
        "include_last_updated_at": "true"
    }

    try:
        response = requests.get(url, params=params)
        response.raise_for_status()
        data = response.json()
        if coin not in data:
            return {"error": "Cryptocurrency not found."}
        return {
            "price": data[coin]["usd"],
            "market_cap": data[coin]["usd_market_cap"],
            "24h_volume": data[coin]["usd_24h_vol"],
            "24h_change": data[coin]["usd_24h_change"],
            "last_updated_at": data[coin]["last_updated_at"]
        }
    except requests.exceptions.RequestException as e:
        return {"error": f"API request failed: {e}"}
    except Exception as e:
        return {"error": f"An unexpected error occurred: {e}"}
